render(() => {
    const [minor, setMinor] = React.useState(true);
    const [currency, setCurrency] = React.useState(false);
    const [rightAddons, setRightAddons] = React.useState(false);
    const [rightAddonsWithIcon, setRightAddonsWithIcon] = React.useState(false);

    const handleMinorChange = () => setMinor(!minor);
    const handleCurrencyChange = () => setCurrency(!currency);
    const handleRightAddonsChange = () => {
        setRightAddons(!rightAddons);
        setRightAddonsWithIcon(false);
    };
    const handleRightAddonsWithIconChange = () => {
        setRightAddonsWithIcon(!rightAddonsWithIcon);
        setRightAddons(false);
    };

    const styleAddons = {
        borderRadius: '99px',
        background: 'linear-gradient(264deg, #FF42CA 0%, #FF8A00 100%)',
        boxSizing: 'border-box',
        padding: '6px 12px',
        display: 'inline-flex',
        verticalAlign: 'bottom',
        marginLeft: '4px',
    };

    const rightAddonsContent = rightAddons && (
        <span style={styleAddons}>
            <Typography.Text
                view='primary-medium'
                weight='medium'
                font='system'
                color='primary-inverted'
            >
                Custom
            </Typography.Text>
        </span>
    );

    const rightAddonsWithIconContent = rightAddonsWithIcon && (
        <span style={{ marginLeft: '5px', display: 'inline-flex' }}>
            <CDNIcon color='var(--color-dark-accent-primary)' name='glyph_diamonds_s' />
        </span>
    );

    return (
        <Container>
            <Typography.Title font='system' view='medium' weight='regular'>
                <AmountComponent
                    value={123456700}
                    minority={100}
                    currency={currency && 'RUB'}
                    view={minor ? 'withZeroMinorPart' : 'default'}
                    rightAddons={rightAddonsContent || rightAddonsWithIconContent}
                />
            </Typography.Title>
            <Gap size={24} />
            <Switch label='Минорная часть' checked={minor} onChange={handleMinorChange} />
            <Gap size={20} />
            <Switch label='Валюта' checked={currency} onChange={handleCurrencyChange} />
            <Gap size={20} />
            <Switch
                label='Кастомный слот'
                checked={rightAddons}
                onChange={handleRightAddonsChange}
            />
            <Gap size={20} />
            <Switch
                label='Кастомный слот с иконкой'
                checked={rightAddonsWithIcon}
                onChange={handleRightAddonsWithIconChange}
            />
        </Container>
    );
});

render(() => {
    const [plus, setPlus] = React.useState(false);

    const handlePlusChange = () => setPlus(!plus);

    return (
        <Container>
            <Typography.Title font='system' view='medium' weight='regular'>
                <AmountComponent
                    value={123456700}
                    minority={100}
                    showPlus={plus}
                    view='withZeroMinorPart'
                />
            </Typography.Title>
            <Gap size={24} />
            <Switch label='Отображать плюс' checked={plus} onChange={handlePlusChange} />
        </Container>
    );
});

render(() => {
    const [minor, setMinor] = React.useState(false);

    const handleMinorChange = () => setMinor(!minor);

    return (
        <Container>
            <Typography.Title font='system' view='medium' weight='regular'>
                <AmountComponent value={123456789} minority={100} view='withZeroMinorPart' />
            </Typography.Title>
            <Gap size={20} />
            <Typography.Title font='system' view='medium' weight='regular'>
                <AmountComponent
                    value={123456700}
                    minority={100}
                    view={minor ? 'default' : 'withZeroMinorPart'}
                />
            </Typography.Title>
            <Gap size={24} />
            <Switch
                label='Не отображать нулевую минорную часть'
                checked={minor}
                onChange={handleMinorChange}
            />
        </Container>
    );
});

render(() => {
    const [textStyle, setTextStyle] = React.useState('headline');
    const [fontWeight, setFontWeight] = React.useState('regular');
    const [transparent, setTransparent] = React.useState('none');

    const onTextStyleChange = React.useCallback((_, payload) => {
        setTextStyle(payload.value);
    }, []);

    const onFontWeightChange = React.useCallback((_, payload) => {
        setFontWeight(payload.value);
    }, []);

    const onTransparentChange = React.useCallback((_, payload) => {
        setTransparent(payload.value);
    }, []);

    const isHeadline = textStyle === 'headline';
    const Component = isHeadline ? Typography.Title : Typography.Text;

    return (
        <Container>
            <Component
                font='system'
                color={textStyle}
                view={isHeadline ? 'medium' : 'primary-large'}
                weight={isHeadline ? 'bold' : 'regular'}
            >
                <AmountComponent
                    value={123456700}
                    minority={100}
                    fontWeight={
                        isHeadline || fontWeight === 'regular'
                            ? undefined
                            : fontWeight.startsWith('major-')
                              ? { major: fontWeight.replace('major-', '') }
                              : fontWeight
                    }
                    currency='RUB'
                    view='withZeroMinorPart'
                    transparentMinor={transparent === 'minor'}
                />
            </Component>
            <Gap size={24} />
            <RadioGroup
                label='Стиль текста'
                direction='vertical'
                name='radioGroup'
                onChange={onTextStyleChange}
                value={textStyle}
            >
                <Radio size={24} label='Заголовок' value='headline' />
                <Radio size={24} label='Обычный текст' value='defaultText' />
                <Radio size={24} label='Зелёный текст' value='positive' />
                <Radio size={24} label='Красный текст' value='accent' />
            </RadioGroup>
            <Gap size={24} />
            <RadioGroup
                label='Модификатор «fontWeight»'
                direction='vertical'
                name='radioGroupFirst'
                onChange={onFontWeightChange}
                value={fontWeight}
            >
                <Radio size={24} label='Без модификатора' value='regular' />
                <Radio size={24} label='Для всей суммы (bold)' value='bold' />
                <Radio size={24} label='Только для мажорной части (bold)' value='major-bold' />
                <Radio size={24} label='Для всей суммы (medium)' value='medium' />
                <Radio size={24} label='Только для мажорной части (medium)' value='major-medium' />
            </RadioGroup>
            <Gap size={24} />
            <RadioGroup
                label='Модификатор «transparent»'
                direction='vertical'
                name='radioGroupFirst'
                onChange={onTransparentChange}
                value={transparent}
            >
                <Radio size={24} label='Без модификатора' value='none' />
                <Radio size={24} label='Только для минорной и валютной части' value='minor' />
            </RadioGroup>
        </Container>
    );
});
